import React from 'react'
import { css } from '@linaria/core'
import { Button, colors } from '@fs/zion-ui'
import { boolAttr } from '@fs/zion-frontend-friends'

const buttonHackCss = css`
  & {
    button,
    a {
      border-radius: 2em;
      text-transform: none;
      font-weight: 600;
      font-size: var(--text-size-b);
      white-space: normal !important;
      overflow: visible;
      word-break: unset;
      max-width: fit-content;
      text-align: center;
      height: auto;
      padding-bottom: 13px;
    }
    button,
    a {
      :not([disabled-button]) {
        --button-text-color: ${colors.gray100};
        --button-hover-background: ${colors.transparent.gray05};
        --button-active-background: ${colors.transparent.gray10};
      }
    }
  }
`

// simplified Rootstech code to match Rootstech button styling
const PillButton = ({ children, ...props }) => {
  const { disabled } = props
  return (
    <div className={buttonHackCss}>
      <Button {...props} disabled-button={boolAttr(disabled)}>
        {children}
      </Button>
    </div>
  )
}

export default PillButton
