import React from 'react'
import { css } from '@linaria/core'
import { Separator, colors, Row, MarginBox, Button } from '@fs/zion-ui'
import { MenuClose } from '@fs/zion-icon'
import { VisuallyHidden } from '@reach/visually-hidden'
import { useTranslation } from 'react-i18next'
import PillButton from './PillButton'
import { useChatState, useChatDispatch } from '../providers/ChatStateProvider'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import { getIsRootstech } from '../helpers/embeddedChatHelper'
import CloseButton from './embedded-chat-header/EmbeddedChatCloseButton'
import useChatLog from '../hooks/useChatLog'
// NOTE: This is supposed to look like skeletons, but skeletons flash and we want
//       it to be static. Hacking the skeletons wasn't any better than all this
//       custom code
const headerCss = css`
  background-color: ${colors.gray05};
  min-height: 56px;
`
const gridCss = css`
  display: grid;
  gap: 10px;
  grid-template-columns: 1fr 11fr;
  margin-block-end: 16px;
`
const contentCss = css`
  margin: 18px;
`
const circleCss = css`
  background-color: ${colors.gray10};
  border-radius: 5em;
  width: 24px;
  height: 24px;
`
const senderCss = css`
  background-color: ${colors.gray10};
  height: 18px;
  width: 60%;
  margin-block: 3px;
  border-radius: 4px;
`
const bodyCss = css`
  background-color: ${colors.gray20};
  margin-block-start: 8px;
  border-radius: 4px;
`
const footerCss = css`
  background-color: ${colors.gray05};
  margin-block-start: -36px;
`

const Message = ({ size = 'sm' }) => {
  return (
    <div className={gridCss}>
      <div className={circleCss} />
      <div>
        <div className={senderCss} />
        <div className={bodyCss} style={{ height: size === 'sm' ? 42 : 98 }} />
      </div>
    </div>
  )
}

const EmbeddedChatFallback = ({ onClose, chatRestricted }) => {
  const [t] = useTranslation()
  const { user } = useChatState()
  const chatDispatch = useChatDispatch()
  const LoginButton = getIsRootstech() ? PillButton : Button
  const { track } = useChatLog({ component: 'EmbeddedChatFallback' })

  const handleClickJoinChat = () => {
    if (!user.signedIn) {
      track({ link_name: 'Chat:embedded-chat-fallback:join-chat:not-signed-in' })
      window.location.href = `/auth/familysearch/login?returnUrl=${encodeURIComponent(window.location.href)}`
    } else {
      track({ link_name: 'Chat:embedded-chat-fallback:join-chat:signed-in' })
      chatDispatch({ type: CHAT_ACTIONS.SET_RENDER_FALLBACK, renderFallback: false })
    }
  }

  return (
    <>
      <MarginBox marginX="nano" className={headerCss}>
        <Separator size="nano" />
        {!!onClose && (
          <Row alignX="end">
            <VisuallyHidden as="h2">{t('chat.join', 'Join Chat')}</VisuallyHidden>
            <CloseButton
              emphasis="high"
              Icon={MenuClose}
              onClick={onClose}
              aria-label={t('common-ui:close.action', 'Close')}
            />
          </Row>
        )}
        <Separator size="nano" />
      </MarginBox>

      <div className={contentCss}>
        <Message size="lg" />
        <Message />
        <Message />
      </div>

      <div className={footerCss}>
        <Separator />
        <Row alignX="center">
          <LoginButton
            disabled={chatRestricted}
            external
            emphasis="medium"
            disabledDescription={t('chat.embedded-chat.fallback', 'This chat is available to those 18 and older.')}
            onClick={handleClickJoinChat}
            description={t('chat.embedded-chat-fallback.description', 'Login required')}
          >
            {t('chat.view', 'View Chat')}
          </LoginButton>
        </Row>
        <Separator />
      </div>
    </>
  )
}

export default EmbeddedChatFallback
